}

class LuxuryHouseBuilder {
    -House house
    +void buildBasic()
    +void buildBody()
    +void buildRoof()
    +House finish()
}

class Decorate {
    -HouseBuilder houseBuilder
    +House construct()
}

class Client {
}

class House {
    -String type
    -boolean base
    -boolean body
    -boolean roof
}

